/**
 * Enum for tool icon names - maps tool IDs to their icon components.
 */
export enum TOOL_ICON_NAME {
  ADD_DATASET = "add_dataset",
  AGGREGATE_POINTS = "aggregate_points",
  AGGREGATE_POLYGON = "aggregate_polygon",
  BUFFER = "buffer",
  CATCHMENT_AREA = "catchment_area",
  CATCHMENT_AREA_V2 = "catchment_area_v2",
  CENTROID = "centroid",
  CLIP = "clip",
  SPATIAL_CLUSTERING = "spatial_clustering",
  CUSTOM_SQL = "custom_sql",
  DISSOLVE = "dissolve",
  DIFFERENCE = "difference",
  EXPORT_DATASET = "export_dataset",
  GEOCODING = "geocoding",
  GEOLOCATION = "geolocation",
  HEATMAP_CLOSEST_AVERAGE = "heatmap_closest_average",
  HEATMAP_CONNECTIVITY = "heatmap_connectivity",
  HEATMAP_GRAVITY = "heatmap_gravity",
  HEATMAP_2SFCA = "heatmap_2sfca",
  HUFF_MODEL = "huff_model",
  INTERSECTION = "intersection",
  JOIN = "join",
  OEV_GUETEKLASSEN = "oev_gueteklassen",
  ORIGIN_DESTINATION = "origin_destination",
  TRAVEL_COST_MATRIX = "travel_cost_matrix",
  TRIP_COUNT = "trip_count",
  UNION = "union",
}

/**
 * Map from TOOL_ICON_NAME to React component.
 */
export const toolIconMap: Record<TOOL_ICON_NAME, React.FC<SvgIconProps>> = {
  [TOOL_ICON_NAME.ADD_DATASET]: AddDatasetIcon,
  [TOOL_ICON_NAME.AGGREGATE_POINTS]: AggregatePointsIcon,
  [TOOL_ICON_NAME.AGGREGATE_POLYGON]: AggregatePolygonsIcon,
  [TOOL_ICON_NAME.BUFFER]: BufferIcon,
  [TOOL_ICON_NAME.CATCHMENT_AREA]: CatchmentAreaIcon,
  [TOOL_ICON_NAME.CATCHMENT_AREA_V2]: CatchmentAreaV2Icon,
  [TOOL_ICON_NAME.CENTROID]: CentroidIcon,
  [TOOL_ICON_NAME.CLIP]: ClipIcon,
  [TOOL_ICON_NAME.SPATIAL_CLUSTERING]: SpatialClusteringIcon,
  [TOOL_ICON_NAME.CUSTOM_SQL]: CustomSqlIcon,
  [TOOL_ICON_NAME.DISSOLVE]: DissolveIcon,
  [TOOL_ICON_NAME.DIFFERENCE]: EraseDifferenceIcon,
  [TOOL_ICON_NAME.EXPORT_DATASET]: ExportDatasetIcon,
  [TOOL_ICON_NAME.GEOCODING]: GeocodingIcon,
  [TOOL_ICON_NAME.GEOLOCATION]: GeolocationIcon,
  [TOOL_ICON_NAME.HEATMAP_CLOSEST_AVERAGE]: HeatmapClosestAverageIcon,
  [TOOL_ICON_NAME.HEATMAP_CONNECTIVITY]: HeatmapConnectivityIcon,
  [TOOL_ICON_NAME.HEATMAP_GRAVITY]: HeatmapGravityIcon,
  [TOOL_ICON_NAME.HEATMAP_2SFCA]: Heatmap2SFCAIcon,
  [TOOL_ICON_NAME.HUFF_MODEL]: HuffModelIcon,
  [TOOL_ICON_NAME.INTERSECTION]: IntersectionIcon,
  [TOOL_ICON_NAME.JOIN]: JoinIcon,
  [TOOL_ICON_NAME.OEV_GUETEKLASSEN]: OevGueteklassenIcon,
  [TOOL_ICON_NAME.ORIGIN_DESTINATION]: OriginDestinationIcon,
  [TOOL_ICON_NAME.TRAVEL_COST_MATRIX]: TravelCostMatrixIcon,
  [TOOL_ICON_NAME.TRIP_COUNT]: TripCountIcon,
  [TOOL_ICON_NAME.UNION]: UnionIcon,
};

/**
 * ToolIcon component - renders two-tone tool icons by name.
 * Usage: <ToolIcon iconName={TOOL_ICON_NAME.BUFFER} sx={{ fontSize: 24 }} />
 */
export function ToolIcon({ iconName, ...rest }: SvgIconProps & { iconName: TOOL_ICON_NAME }): JSX.Element {
  const IconComponent = toolIconMap[iconName];
  if (!IconComponent) throw new Error(`Invalid tool icon name: ${iconName}`);
  return <IconComponent {...rest} />;
}
